// Classic ES5 style - simple, readable
function selectionSortClassic(arr) {
  for (let i = 0; i < arr.length - 1; i++) {
    let minIdx = i;
    for (let j = i + 1; j < arr.length; j++) {
      if (arr[j] < arr[minIdx]) minIdx = j;
    }
    // Swap
    [arr[i], arr[minIdx]] = [arr[minIdx], arr[i]];
  }
  return arr;
}

// ES2025 iterators for lazy evaluation
function* selectionSortGenerator(arr) {
  const copy = [...arr]; // Avoid mutating original
  for (let i = 0; i < copy.length - 1; i++) {
    let minIdx = i;
    for (let j = i + 1; j < copy.length; j++) {
      if (copy[j] < copy[minIdx]) minIdx = j;
    }
    [copy[i], copy[minIdx]] = [copy[minIdx], copy[i]];
    yield copy.slice(0, i + 1); // Yield partial results
  }
  return copy;
}

// Usage: for (const step of selectionSortGenerator([64, 34, 25, 12, 22])) console.log(step);

// ES2022+ TypedArray + Atomics for multithreaded sorting
function selectionSortTyped(arr) {
  const typed = new Float64Array(arr); // Faster memory access
  for (let i = 0; i < typed.length - 1; i++) {
    let minIdx = i;
    for (let j = i + 1; j < typed.length; j++) {
      if (typed[j] < typed[minIdx]) minIdx = j;
    }
    Atomics.exchange(typed, i, typed[minIdx]); // Atomic swap
    Atomics.store(typed, minIdx, typed[i]);
  }
  return Array.from(typed);
}
